private void copyAttributes(org.jsoup.nodes.Node source, Element el) {
    if (source == null || el == null) {
        return;
    }
    for (Attribute attribute : source.attributes()) {
        if (attribute == null) {
            continue;
        }
        // valid xml attribute names are: ^[a-zA-Z_:][-a-zA-Z0-9_:.]
        String key = attribute.getKey().replaceAll("[^-a-zA-Z0-9_:.]", "");
        if (!key.isEmpty() && Character.isLetterOrDigit(key.charAt(0))) {
            el.setAttribute(key, attribute.getValue());
        }
    }
}

private void copyAttributes(org.jsoup.nodes.Node source, Element el) {
    for (Attribute attribute : source.attributes()) {
        String key = attribute.getKey();
        String value = attribute.getValue();
        if (key == null || value == null) continue;
        if (!key.matches("^[a-zA-Z_:][-a-zA-Z0-9_.:]*$")) continue;
        el.setAttribute(key, value);
    }
}

private void copyAttributes(org.jsoup.nodes.Node source, Element el) {
    if (source == null || el == null) return;
    for (Attribute attribute : source.attributes()) {
        if (attribute == null) continue;
        String key = attribute.getKey();
        // valid xml attribute names including namespaces are: ^([a-zA-Z_:][-a-zA-Z0-9_:.]*)?:([-a-zA-Z0-9_:.]+)?$
        if (!key.matches("^([a-zA-Z_:][-a-zA-Z0-9_:.]*)?:([-a-zA-Z0-9_:.]+)?$")) continue;
        el.setAttribute(key, attribute.getValue());
    }
}

private void copyAttributes(org.jsoup.nodes.Node source, Element el) {
    for (Attribute attribute : source.attributes()) {
        // valid xml attribute names are: ^[a-zA-Z_:][-a-zA-Z0-9_:.]*$
        String key = attribute.getKey();
        if (key == null || key.isEmpty()) continue;
        String sanitizedKey = key.replaceAll("[^-a-zA-Z0-9_:.]", "");
        if (sanitizedKey.isEmpty() || !sanitizedKey.matches("^[a-zA-Z_:][-a-zA-Z0-9_.:]*$")) continue;
        el.setAttribute(sanitizedKey, attribute.getValue());
    }
}

private void copyAttributes(org.jsoup.nodes.Node source, Element el) {
    for (Attribute attribute : source.attributes()) {
        // Check for null attribute key or value
        if (attribute == null || attribute.getKey() == null || attribute.getValue() == null) continue;
        // valid xml attribute names are: ^[a-zA-Z_:][-a-zA-Z0-9_:.]*$
        String key = attribute.getKey().trim();
        if (!key.matches("^[a-zA-Z_:][-a-zA-Z0-9_:.]*$")) continue;
        el.setAttribute(key, attribute.getValue());
    }
}
